"""seed."""
import numpy as np


def construct_packing():
    n = 26
    rows, cols = 6, 5
    r = 0.5 / max(rows, cols)
    r *= 0.95
    centers = []
    for i in range(rows):
        for j in range(cols):
            if len(centers) >= n:
                break
            cx = r + j * (1.0 - 2 * r) / max(cols - 1, 1)
            cy = r + i * (1.0 - 2 * r) / max(rows - 1, 1)
            centers.append([cx, cy])
        if len(centers) >= n:
            break
    centers = np.array(centers[:n])
    radii = np.full(n, r)
    return centers, radii, float(np.sum(radii))
# EVOLVE-BLOCK-END

def run_packing():
    return construct_packing()
